mapper.select:
SELECT result_id::text
  FROM evd_evidence_command_result
 WHERE tenant_id = #{tenantId}
   AND operation_type = #{operationType}
   AND idempotency_key = #{idempotencyKey}

mapper.update:
UPDATE evd_evidence_revision
   SET status = #{status}
 WHERE tenant_id = #{tenantId}
   AND evidence_revision_id = CAST(#{revisionId} AS uuid)
   AND status = #{expectedStatus}

UPDATE evd_evidence_slot
   SET status_projection = #{status}
 WHERE tenant_id = #{tenantId}
   AND slot_id = CAST(#{slotId} AS uuid)
